205→    const userId = user?.userData?.[0]?.id || null;
206→    const isSearchMode = committedSearchQuery.length >= 2;
207→
208→    useEffect(() => {
209→        const timer = setTimeout(() => {
210→            setDebouncedSearchInput(searchInput.trim());
211→        }, 350);
212→
213→        return () => clearTimeout(timer);
214→    }, [searchInput]);
215→
216→    const {
217→        data,
218→        fetchNextPage,
219→        hasNextPage,
220→        isFetchingNextPage,
221→        isLoading: isFeedLoading,
222→    } = useInfiniteQuery({
223→        queryKey: ['journals', userId],
224→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
225→        getNextPageParam: (lastPage) => {
226→            if(lastPage?.hasMore) {
227→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
228→                return new Date(lastJournal.created_at).toISOString();
229→            }
230→            return undefined;
231→        } ,
232→        refetchOnWindowFocus: false
233→    })
234→
235→    const {
236→        data: searchData,
237→        isLoading: isSearchLoading,
238→        isFetching: isSearchFetching,
239→        error: searchError,
240→    } = useQuery({
241→        queryKey: ['journals-search', userId, committedSearchQuery],
242→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
243→        enabled: isSearchMode,
244→        refetchOnWindowFocus: false,
245→        staleTime: 15 * 1000,
246→    });
247→
248→    const {
249→        data: suggestionData,
250→        isLoading: isSuggestionsLoading,
251→    } = useQuery({
252→        queryKey: ['journals-suggestions', userId, debouncedSearchInput],
253→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
254→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused,
255→        refetchOnWindowFocus: false,
256→        staleTime: 10 * 1000,
257→    });
