259→    const handleClickSettings = (e, postId) =>{
260→        e.stopPropagation();
261→        setPostIdSettings(postId === postIdSettings ? null : postId)
262→    }
263→
264→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
265→
266→    const handleClickLike = async (journalId, receiverId) => {
267→        if(!session) return openAuthModal();
268→        console.log(journalId)
269→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
270→    }
271→
272→
273→    const mutationBookmark = useBookMarkMutation(session, userId);
274→
275→    const handleClickBookmark = async (journalId) => {
276→        if(!session) return openAuthModal();
277→        console.log(journalId)
278→        // mutationBookmark.mutate({journalId});
279→        const response = await mutationBookmark.mutateAsync({journalId})
280→
281→        if(timeOutRef.current){
282→            clearTimeout(timeOutRef.current);
283→        }
284→        if(response.message === 'success'){
285→            setBookmarkedMessage('Post was added to your Bookmarks')
286→            setShowBookmarkedMessage(journalId);
287→            timeOutRef.current = setTimeout(() =>{
288→                setShowBookmarkedMessage(null)
289→                setBookmarkedMessage('')
290→            }, 2500)
291→        } else {
292→            setBookmarkedMessage('Post was removed from your Bookmarks')
293→            setShowBookmarkedMessage(journalId);
294→            timeOutRef.current = setTimeout(() =>{
295→                setShowBookmarkedMessage(null)
296→                setBookmarkedMessage('')
297→            }, 2500)
298→        }
299→        console.log(response.message);
300→    }
301→
302→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
303→
304→    const handleSubmitSearch = (rawQuery) => {
305→        const normalizedQuery = typeof rawQuery === 'string' ? rawQuery.trim() : '';
306→        if(normalizedQuery.length < 2){
307→            setCommittedSearchQuery('');
308→            return;
309→        }
310→
311→        setCommittedSearchQuery(normalizedQuery);
312→        setSearchInput(normalizedQuery);
313→        setIsSearchFocused(false);
314→    };
315→
316→    const handleClearSearch = () => {
317→        setSearchInput('');
318→        setDebouncedSearchInput('');
319→        setCommittedSearchQuery('');
320→        setIsSearchFocused(false);
321→    };
322→
323→    const handleSearchInputKeyDown = (e) => {
324→        if(e.key === 'Enter'){
325→            e.preventDefault();
326→            handleSubmitSearch(searchInput);
327→        }
328→
329→        if(e.key === 'Escape'){
330→            setIsSearchFocused(false);
331→        }
332→    };
333→
334→    const handleClickSuggestion = (journal) => {
335→        if(!journal?.id){
336→            return;
337→        }
338→        setIsSearchFocused(false);
339→        if(journal?.title){
340→            setSearchInput(journal.title);
341→            setDebouncedSearchInput(journal.title);
342→        }
343→        navigate(`/home/post/${journal.id}`);
344→    };
345→
346→    const handleVisitFreedomWall = () => {
347→        navigate('/home/freedom-wall');
348→    };
349→
350→    useEffect(() => {
351→        const handleOutsideSearchClick = (e) => {
352→            if(searchShellRef.current && !searchShellRef.current.contains(e.target)){
353→                setIsSearchFocused(false);
354→            }
355→        };
356→
357→        window.addEventListener('mousedown', handleOutsideSearchClick);
358→        return () => window.removeEventListener('mousedown', handleOutsideSearchClick);
359→    }, []);
360→
361→    useEffect(() =>{
362→        if(!isSearchMode && inView && hasNextPage && !isFetchingNextPage) {
363→            fetchNextPage();
364→        }
365→    }, [inView, fetchNextPage, hasNextPage, isFetchingNextPage, isSearchMode])
366→
367→
368→    useEffect(() => {
369→       const handleClickOutside = (e) =>{
370→        if(modalRef.current && !modalRef.current.contains(e.target)){
371→            setPostIdSettings(null)
372→        }
373→       }
374→       window.addEventListener('click', handleClickOutside)
375→
376→       return() => {
377→        window.removeEventListener('click', handleClickOutside)
378→       }
379→    }, [])
380→
381→    useEffect(() =>{
382→        const scroll = (e) =>{
383→            setShowHeaders(!showHeaders)
384→
385→            if(timeOutRef.current){
386→                clearTimeout(timeOutRef.current);
387→            }
388→            timeOutRef.current = setTimeout(() => {
389→                setShowHeaders(showHeaders)
390→            }, 100);
391→        }
392→        document.addEventListener('scroll', scroll, true);
393→        return() =>{
394→            if(timeOutRef.current){
395→                clearTimeout(timeOutRef.current);
396→            }
397→            document.removeEventListener('scroll', scroll, true)
398→        }
