402→    const searchedJournals = searchData?.data || [];
403→    const suggestionItems = suggestionData?.data || [];
404→    const journals = isSearchMode ? searchedJournals : feedJournals;
405→    const isLoading = isSearchMode ? isSearchLoading : isFeedLoading;
406→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
407→
408→    if(isLoading) {
409→        return(
410→            <>
411→            <div className="postcards-parent-loading-container">
